+    function enforceCanonicalHost() {
+        const host = window.location.hostname.toLowerCase();
+        if (!CANONICAL_HOSTS.has(host)) return false;
+        if (window.location.origin === CANONICAL_ORIGIN) return false;
+        const target = new URL(window.location.href);
+        target.protocol = "https:";
+        target.host = "frankensqlite.com";
+        window.location.replace(target.toString());
+        return true;
+    }
+
+    function sqliteMagicPrefix(bytes) {
+        return new TextDecoder().decode(bytes.slice(0, 15));
+    }
+
+    function buildDbCandidates() {
+        const candidates = [];
+        const seen = new Set();
+        const push = (value) => {
+            let parsed;
+            try {
+                parsed = new URL(value, window.location.origin);
+            } catch {
+                return;
+            }
+            const href = parsed.toString();
+            if (seen.has(href)) return;
+            seen.add(href);
+            candidates.push(href);
+        };
+
+        push(DB_URL);
+        push(`/${DB_FILENAME}`);
+        push(DB_FILENAME);
+        push(`${CANONICAL_ORIGIN}/${DB_FILENAME}`);
+
+        // Some stale clients cached a query-string DB URL; always retry stripped variants.
+        for (const href of [...candidates]) {
+            const stripped = new URL(href);
+            stripped.search = "";
+            stripped.hash = "";
+            push(stripped.toString());
+        }
+        return candidates;
+    }
+
+    async function loadSqliteBytes() {
+        const candidates = buildDbCandidates();
+        const failures = [];
+        for (const candidate of candidates) {
+            try {
+                const buf = await fetchAsArrayBuffer(candidate);
+                const bytes = new Uint8Array(buf);
+                const magic = sqliteMagicPrefix(bytes);
+                if (magic === "SQLite format 3") {
+                    return bytes;
+                }
+                failures.push(`${candidate} -> not SQLite (${bytes.byteLength} bytes, starts with "${magic.slice(0,12)}...")`);
+            } catch (e) {
+                failures.push(`${candidate} -> ${e.message || String(e)}`);
+            }
+        }
+        throw new Error(`Could not load SQLite database after trying ${candidates.length} URL(s): ${failures.join(" | ")}`);
+    }
